 1	import React from 'react';
 2	import { Table, TableProps } from '@patternfly/react-table';
 3	import { useDeepCompareMemo } from 'use-deep-compare';
 4	import { TableBatteries } from '../types';
 5	
 6	export const useTableWithBatteries = <
 7	  TItem,
 8	  TColumnKey extends string,
 9	  TSortableColumnKey extends TColumnKey,
10	  TFilterCategoryKey extends string = string,
11	  TPersistenceKeyPrefix extends string = string
12	>(
13	  batteries: Omit<
14	    TableBatteries<TItem, TColumnKey, TSortableColumnKey, TFilterCategoryKey, TPersistenceKeyPrefix>,
15	    'components'
16	  >
17	): React.ForwardRefExoticComponent<Omit<TableProps, 'ref'>> => {
18	  const { propHelpers } = batteries;
19	  const TableWithBatteries = useDeepCompareMemo(
20	    () =>
21	      React.forwardRef((props: Omit<TableProps, 'ref'>, ref: React.Ref<HTMLTableElement>) => (
22	        <Table {...propHelpers.tableProps} innerRef={ref as React.MutableRefObject<HTMLTableElement>} {...props} />
23	      )),
24	    [propHelpers.tableProps]
25	  );
26	  TableWithBatteries.displayName = 'TableWithBatteries';
27	  return TableWithBatteries;
28	};

